3	struct ContentView: View {
4	    @Bindable var store: DemoVehicleStateStore
5	    let traceLogger: InMemoryTraceLogger
6	    let speech: any SpeechSynthesisEngine
7	
8	    @State private var commandText = "打开空调"
9	    @State private var lastReadback = "等待指令"
10	    @State private var errorText: String?
11	
12	    var body: some View {
13	        NavigationStack {
14	            VStack(alignment: .leading, spacing: 20) {
15	                commandBar
16	                vehicleCards
17	                tracePanel
18	            }
19	            .padding(24)
20	            .navigationTitle("MAformac")
21	        }
22	    }
23	
24	    private var commandBar: some View {
25	        HStack(spacing: 12) {
26	            TextField("输入车控指令", text: $commandText)
27	                .textFieldStyle(.roundedBorder)
28	
29	            Button {
30	                Task { await runCommand() }
31	            } label: {
32	                Label("执行", systemImage: "play.fill")
33	            }
34	            .buttonStyle(.borderedProminent)
35	        }
36	        .accessibilityIdentifier("command-bar")
37	    }
38	
39	    private var vehicleCards: some View {
40	        LazyVGrid(columns: [GridItem(.adaptive(minimum: 160), spacing: 12)], spacing: 12) {
41	            ForEach(store.cells) { cell in
42	                VehicleStateCard(cell: cell)
43	            }
44	        }
45	    }
46	
47	    private var tracePanel: some View {
48	        VStack(alignment: .leading, spacing: 8) {
49	            Text(lastReadback)
50	                .font(.headline)
51	            if let errorText {
52	                Text(errorText)
53	                    .foregroundStyle(.red)
54	            }
55	            ForEach(Array(traceLogger.entries.enumerated()), id: \.offset) { _, entry in
56	                Text("\(entry.stage.rawValue): \(entry.message)")
57	                    .font(.caption.monospaced())
58	                    .foregroundStyle(.secondary)
59	            }
60	        }
61	        .accessibilityIdentifier("trace-panel")
62	    }
63	
64	    @MainActor
65	    private func runCommand() async {
66	        errorText = nil
67	        let skeleton = DemoWalkingSkeleton(
68	            store: store,
69	            guardrail: DemoFastPathGuard(),
70	            traceLogger: traceLogger,
71	            speech: speech
72	        )
73	
74	        do {
75	            let readback = try await skeleton.handle(text: commandText)
76	            lastReadback = "\(readback.key): \(readback.actualValue)"
77	        } catch {
78	            errorText = "\(error)"
79	        }
80	    }
81	}
82	
83	private struct VehicleStateCard: View {
84	    let cell: DemoVehicleStateCell
85	
86	    var body: some View {
87	        VStack(alignment: .leading, spacing: 8) {
88	            Text(title)
89	                .font(.headline)
90	            Text(cell.actualValue)
91	                .font(.title2.weight(.semibold))
92	            Text("rev \(cell.revision)")
93	                .font(.caption.monospacedDigit())
94	                .foregroundStyle(.secondary)
95	        }
96	        .frame(maxWidth: .infinity, alignment: .leading)
97	        .padding(14)
98	        .background(background)
99	        .clipShape(RoundedRectangle(cornerRadius: 8, style: .continuous))
100	        .overlay {
101	            RoundedRectangle(cornerRadius: 8, style: .continuous)
102	                .strokeBorder(borderColor, lineWidth: 1)
103	        }
104	        .accessibilityIdentifier("vehicle-card-\(cell.key)")
105	    }
106	
107	    private var title: String {
108	        switch cell.key {
109	        case "hvac.ac": return "空调"
110	        case "hvac.temperature": return "温度"
111	        case "seat.driver.heat": return "座椅加热"
112	        case "seat.driver.ventilation": return "座椅通风"
113	        case "window.driver": return "车窗"
114	        case "lighting.ambient": return "氛围灯"
115	        case "screen.brightness": return "屏幕亮度"
116	        case "fan.speed": return "风量"
117	        default: return cell.key
118	        }
119	    }
120	
121	    private var background: Color {
122	        cell.visualState == .satisfied ? Color.green.opacity(0.18) : Color.gray.opacity(0.10)
123	    }
124	
125	    private var borderColor: Color {
126	        cell.visualState == .satisfied ? .green : .gray.opacity(0.35)
127	    }
128	}
129	
130	#Preview {
131	    ContentView(
132	        store: DemoVehicleStateStore(),
133	        traceLogger: InMemoryTraceLogger(),
134	        speech: RecordingSpeechSynthesisEngine()
135	    )
136	}
